{
  "product_category": "bottle",
  "defect_type": "contamination",
  "defect_presence": "present",
  "background_description": "A top-down view of a dark amber glass bottle neck. The object features concentric circular rings forming the rim and sealing area. The glass has a smooth, glossy finish with orange-brown highlights from the lighting. The center is a dark, empty circular void representing the bottle interior.",
  "defect_description": "Small, bright white to light-gray irregular particles and specks. They appear as foreign debris resting on the dark glass surface. The particles vary in size from tiny dots to small irregular shapes, contrasting sharply with the dark background.",
  "relative_position_description": "Scattered along the inner ring and rim of the bottle neck, with notable particles on the right side and isolated specks at the bottom and left edges.",
  "layout_region": {
    "coarse_region": "scattered",
    "object_anchor": "along the inner rim and sealing ring",
    "rough_defect_bbox_xyxy": null
  }
}

{
  "product_category": "cable",
  "defect_type": "combined",
  "defect_presence": "present",
  "background_description": "A cross-sectional view of a multi-core electrical cable resting on a dark, textured gray surface. The cable features a thick white outer sheath containing three insulated conductors: a yellow-green one, a blue one, and a brown one. Each conductor contains a bundle of stranded copper wires. The lighting is even, revealing the texture of the insulation and metal strands.",
  "defect_description": "The outer white sheath exhibits significant structural damage. There is a large, deep split or crack on the right side, extending from the outer perimeter inward, effectively separating a segment of the sheath material with sharp, irregular edges. Additionally, there are smaller cracks, pits, and surface irregularities along the bottom edge of the white sheath, appearing as indentations or fractures in the material.",
  "relative_position_description": "The major split is located on the right side of the outer sheath, extending from the outer edge towards the central conductors. Secondary cracks and surface damage are present along the bottom edge of the sheath.",
  "layout_region": {
    "coarse_region": "scattered",
    "object_anchor": "on the right side and bottom edge of the outer sheath",
    "rough_defect_bbox_xyxy": null
  }
}

{
  "product_category": "cable",
  "defect_type": "cut",
  "defect_presence": "present",
  "background_description": "A circular cross-section of a multi-core electrical cable resting on a speckled gray surface. The cable features a thick, white outer sheath with a smooth, slightly porous texture. Inside, three smaller circular conductors are arranged in a triangular formation, each with distinct colored plastic insulation in green, blue, and brown/gray surrounding a central core.",
  "defect_description": "The inner plastic insulation of all three conductors is sliced open, creating large, irregular openings. The insulation material is peeled and split back with jagged, rough edges, fully exposing the underlying bundles of shiny copper strands. The cuts compromise the protective layer of each core.",
  "relative_position_description": "Located on the inner insulation of the three cores: the green core's insulation is cut at its lower edge, the blue core's insulation is split on its upper-left side, and the brown core's insulation is cut at its upper edge.",
  "layout_region": {
    "coarse_region": "center",
    "object_anchor": "on the inner insulation of the three cores",
    "rough_defect_bbox_xyxy": null
  }
}

{
  "product_category": "cable",
  "defect_type": "missing_wire",
  "defect_presence": "present",
  "background_description": "A cross-sectional view of a multi-core cable with a thick white outer sheath. Inside, three circular insulated conductors are arranged in a triangular formation: one blue, one brown, and one yellow-green. The blue conductor displays a dense, shiny cluster of copper strands in its center. The insulation surfaces are smooth and matte under even lighting.",
  "defect_description": "The central areas of the yellow-green and brown conductors are largely empty dark voids, lacking the dense bundle of copper strands seen in the blue conductor. Only one or two tiny copper fragments are visible within the dark central holes, indicating the internal copper wires are almost entirely absent. The empty spaces have scalloped edges corresponding to the inner insulation wall.",
  "relative_position_description": "In the central cores of the upper yellow-green conductor and the lower-right brown conductor.",
  "layout_region": {
    "coarse_region": "scattered",
    "object_anchor": "inside the upper and lower-right inner conductors",
    "rough_defect_bbox_xyxy": null
  }
}
